mapper.select:
SELECT tb.*
FROM trip_block tb
JOIN trip_candidate tc ON tc.id = tb.candidate_id
WHERE tc.trip_id = #{tripId}
  AND tb.trip_date = #{date}
ORDER BY tb.display_order

mapper.delete:
DELETE FROM trip_block
WHERE candidate_id IN (
    SELECT id FROM trip_candidate WHERE trip_id = #{tripId}
)
